class Patient:
    def __init__(self, name, age, room_number):
        self.name = name
        self.age = age
        self.room_number = room_number

    def __str__(self):
        return f"{self.name}, {self.age}, Room {self.room_number}"

class Hospital:
    def __init__(self):
        self.patients = []

    def add_patient(self, patient):
        self.patients.append(patient)

    def print_patients(self):
        for patient in self.patients:
            print(patient)

    def search_patient(self, name):
        for patient in self.patients:
            if patient.name == name:
                return patient
        return None

    def alter_patient(self, name, attribute, value):
        patient = self.search_patient(name)
        if patient is not None:
            setattr(patient, attribute, value)
        else:
            print("Patient not found.")

# Create a hospital
hospital = Hospital()

# Add patients
hospital.add_patient(Patient("John Doe", 30, 101))
hospital.add_patient(Patient("Jane Smith", 25, 102))
hospital.add_patient(Patient("Bob Johnson", 40, 103))

# Print all patients
print("All patients:")
hospital.print_patients()

# Alter patient
hospital.alter_patient("John Doe", "age", 35)

# Print all patients again
